var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아, 진짜. 옷에 구멍 숭숭 뚫렸잖아.","JPN":"ったく。服に穴が開いたじゃない。","ENG":"Oh, man. My clothes have holes now.","TWN":"吼唷，討厭，衣服都破了啦！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"모처럼 받은 의뢰라 신경 좀 썼더니…….","JPN":"せっかく受けた依頼だから気合入れてきたのに……","ENG":"All I wanted was to do my best to accomplish the task...","TWN":"想說好不容易才接到委託，還特地打扮一下……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그나저나 어제 그 녀석들, 길바닥에 굴러다니는 허접들에 비하면 실력이 꽤 좋았단 말이지.","JPN":"そういや昨日のやつら、そこらに転がっている底辺どもに比べたら実力はある方だったな。","ENG":"By the way, those new girls were pretty good, compared to other idiots.","TWN":"不過，昨天那些傢伙，不像其他的二百五，好像滿會打的。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"묘하게 침식체가 아니라 사람이랑 더 많이 싸워 본 것 같던데…….","JPN":"妙に侵食体じゃなくて、人と戦った経験の方が豊富そうだったけど……","ENG":"They seemed more proficient in fighting humans than C.O.s...","TWN":"只是有點奇妙，他們戰鬥的對象好像比較多是人，而不是侵蝕體……"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"코핀 컴퍼니가 불렀나? 아니면 설마 그 촌뜨기들이?","JPN":"コフィンカンパニーが呼んだのかな？　それともまさかあの田舎者たちが？","ENG":"Did the Coffin Company summon them? Or those hillbillies?","TWN":"是科芬公司找來的嗎？還是那些土包子？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"흥. 뭐 어때. 어차피 오늘이면 이 지겨운 의뢰랑도 작별일 텐데.","JPN":"ふーん、まあいいや。どうせ今日でこのうんざりする依頼ともお別れだし。","ENG":"Hmpf, whatever. This dreadful contract will be over today.","TWN":"哼，不管啦！反正今天就是要把這個討厭的委託給結束掉！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"돌아가는 대로 완수금으로 새로운 배나 한 척 뽑아야지.","JPN":"戻ったら完遂金で新しい船でも一隻買おっと。","ENG":"I’ll buy a new ship as soon as I get the money.","TWN":"我回去要立刻用委託金買一艘新的船！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"최신 사양의 럭셔리 보트로 말이야. 캬하핫!","JPN":"最新仕様のラグジュアリーボートだ、キャハハッ！","ENG":"The most expensive one. Kya hah hah!","TWN":"而且還是全新豪華配備版的遊艇，哇哈哈哈！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"후후……. 후후훗…….","JPN":"ふふ……ふふふっ……","ENG":"Heh heh... Heh heh heh...","TWN":"呵呵… 呵呵呵…"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"나 왔어, 박사님.","JPN":"戻ったぞ、博士。","ENG":"Hey, doctor.","TWN":"博士，我來囉～"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"박사님이 이번에 새로 만든 침식체들, 효과 끝내 주더라?","JPN":"博士が今回新しく作った侵食体、最高だったよ。","ENG":"Your new C.O.s did great!","TWN":"博士這次新做的侵蝕體效果超棒欸！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"의뢰주한테서 오늘 일 끝나면 풀어 주라고 확답 받았어. 진즉 이랬으면 좋았잖아.","JPN":"依頼主から今日の仕事が終わったら解放してやれと確答されたよ。博士もさっさとこうしとけばよかったのにな。","ENG":"The client told me to let you go once the job is finished today. You should have done it sooner, doctor.","TWN":"委託人保證說，只要今天把事情搞定，就會放了你，是不是很棒？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그래요. 처음부터 이래야 했어요.","JPN":"そうです。最初からこうするべきでした。","ENG":"Yes, I should have done this sooner.","TWN":"沒錯，一開始就該這樣！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"휴양지에 바퀴벌레처럼 기어들어 올 커플들에게…… 잊지 못할 휴가를 선사해 주기 위해.","JPN":"リゾート地にゴキブリのごとく集まってきたカップルたちに……一生忘れられないバカンスの思い出を作らせるために。","ENG":"I should have given all these disgustingly lovely couples on the beach... a nightmarish vacation...","TWN":"那些像蟑螂一樣潛入度假村情侶…我要送你們一個難忘的假期。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"응……?","JPN":"え……？","ENG":"Huh?","TWN":"嗯…？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"내가 잘못 들었나? 갑자기 왜 안 하던 헛소리를 하고 그래?","JPN":"あたしの聞き間違い？　急にどういうこと？","ENG":"What did you say? What the heck are you talking about?","TWN":"我有聽錯嗎？你在跟我雞同鴨講嗎？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};